import{SupervisorService}from"./supervisor.service.js";async function initSupervisor(){let t=document.querySelector(".cuerpoTabla");var a;t&&(a=await SupervisorService.get_all_supervisores(),t.innerHTML="",console.log(a),a.forEach(a=>{t.innerHTML+=`
            <tr>
                <td>${a.id_supervisor}</td>
                <td>${a.nombre}</td>
                <td>${a.cedula}</td>
                <td>
                    <button class="btn btn-danger" data-bs-toggle="modal" data-bs-target="#ModalEliminar" data-id="${a.id_supervisor}">
                        <i class="bi bi-trash"></i>
                    </button>
                    <button class="btn btn-warning" data-bs-toggle="modal" data-bs-target="#ModalEditar" data-id="${a.id_supervisor}">
                        <i class="bi bi-pencil"></i>
                    </button>
                </td>
            </tr>
        `}),$.fn.DataTable.isDataTable("#dataTable")&&$("#dataTable").DataTable().destroy(),$("#dataTable").DataTable({responsive:!0}),console.log(document.querySelector(".cuerpoTabla")))}export{initSupervisor};